Code:
public int luckySum(int a, int b, int c) {
    int sum = 0;

    if (a == 13) {
        return sum;
    }
    sum += a;

    if (b == 13) {
        return sum;
    }
    sum += b;

    if (c == 13) {
        return sum;
    }
    sum += c;

    return sum;
}

